  enterInvalidCredentials() {
    this.enterUsername('invalid@user.com');
    this.enterPassword('WrongPassword123');
  }

  /**
   * Enter empty username (leave field blank)
   */
  enterEmptyUsername() {
    cy.get(selectors.emailField).clear();
  }

